// PostgreSQL Quota Checker Implementation
class PostgreSQLQuotaChecker extends AzureQuotaChecker {
    constructor(azureClient) {
        super(azureClient);
    }
    getSkuDetail(name, remainingQuota) {
        // Microsoft.DBforPostgreSQL/flexibleServers: cores, standardBSFamily, standardDADSv5Family, standardDDSv4Family, standardDDSv5Family, standardDSv3Family, standardEADSv5Family, standardEDSv4Family, standardEDSv5Family, standardESv3Family
        if (name.startsWith("standardB")) {
            return `${name} (Burstable tier)`;
        }
        if (name.startsWith("standardD")) {
            let skuParts = name.slice(9).split('Family')[0];
            return `${name} (GeneralPurpose tier, e.g. Standard_D2${skuParts.slice(0, skuParts.length - 2).toLowerCase()}_${skuParts.slice(-2)})`;
        }
        if (name.startsWith("standardE")) {
            let skuParts = name.slice(9).split('Family')[0];
            return `${name} (MemoryOptimized tier, e.g. Standard_E2${skuParts.slice(0, skuParts.length - 2).toLowerCase()}_${skuParts.slice(-2)})`;
        }
        if (name === "cores") {
            return `${name} (remaining quota: ${remainingQuota})`;
        }
        return `${name}`;
    }
    async getQuotaForLocation(location) {
        try {
            const requestUrl = `https://management.azure.com/subscriptions/${this.azureClient.getCurrentSubscriptionId()}/providers/Microsoft.DBforPostgreSQL/locations/${location}/resourceType/flexibleServers/usages?api-version=2023-06-01-preview`;
            const rawResponse = await this.azureClient.queryManagementPlane(requestUrl);
            if (!rawResponse || !rawResponse.value) {
                return emptyQuotaInfo;
            }
            if (rawResponse.value.some((q) => q.name.value === "cores" && q.limit - q.currentValue < 2)) {
                return emptyQuotaInfo;
            }
            return rawResponse.value.map((item) => ({
                name: this.getSkuDetail(item.name?.value || '', item.limit - item.currentValue),
                limit: item.limit || 0,
                used: item.currentValue || 0,
                unit: item.unit
            }));
        }
        catch (error) {
            console.error(`Error fetching PostgreSQL quotas: ${error}`);
            return [];
        }
    }
}
exports.PostgreSQLQuotaChecker = PostgreSQLQuotaChecker;
