// Factory function to create quota checkers
function createQuotaChecker(provider, azureClient) {
    const values = Object.values(ResourceProvider);
    const matchingProvider = values.find(enumValue => enumValue === provider);
    if (!matchingProvider) {
        throw new Error(`Unsupported resource provider: ${provider}`);
    }
    switch (matchingProvider) {
        case ResourceProvider.Compute:
            return new ComputeQuotaChecker(azureClient);
        case ResourceProvider.CognitiveServices:
            return new CognitiveServicesQuotaChecker(azureClient);
        case ResourceProvider.Storage:
            return new StorageQuotaChecker(azureClient);
        case ResourceProvider.ContainerApp:
            return new ContainerAppQuotaChecker(azureClient);
        case ResourceProvider.Network:
            return new NetworkQuotaChecker(azureClient);
        case ResourceProvider.MachineLearning:
            return new MachineLearningQuotaChecker(azureClient);
        case ResourceProvider.PostgreSQL:
            return new PostgreSQLQuotaChecker(azureClient);
        case ResourceProvider.HDInsight:
            return new HDInsightQuotaChecker(azureClient);
        case ResourceProvider.Search:
            return new SearchQuotaChecker(azureClient);
        case ResourceProvider.ContainerInstance:
            return new ContainerInstanceQuotaChecker(azureClient);
        case ResourceProvider.SQL:
            console.log("Checking for SQL provider");
            return new SQLQuotaChecker(azureClient);
        case ResourceProvider.AppServiceManagedInstance:
            return new AppServiceManagedInstanceQuotaChecker(azureClient);
        default:
            throw new Error(`No implementation for provider: ${provider}`);
    }
}
// Function to get Azure quota for a list of resource types
async function GetAzureQuota(resourceTypes, azureClient, location) {
    const result = {};
    const processedProviders = new Set();
    const quotaPromises = resourceTypes.map(resourceType => new Promise(async (resolve) => {
        try {
            const provider = resourceType.split('/')[0];
            if (processedProviders.has(provider)) {
                resolve();
                return;
            }
            processedProviders.add(provider);
            const quotaChecker = createQuotaChecker(provider, azureClient);
            console.log(`Checking for quota ${location}`);
            const quotaInfo = await quotaChecker.getQuotaForLocation(location);
            resourceTypes
                .filter(rt => rt.split('/')[0] === provider)
                .forEach(rt => {
                result[rt] = quotaInfo;
            });
        }
        catch (error) {
            result[resourceType] = [];
        }
        resolve();
    }));
    await Promise.all(quotaPromises);
    return result;
}
